const input = $input.first().json;

const doc = {
  file_name: input.file_name || 'unnamed',
  file_url: input.file_url || '',
  file_type: input.file_type || 'unknown',
  file_size: input.file_size || 0,
  source: input.source || 'manual_upload',
  uploaded_by: input.uploaded_by || 'system',
  department: input.department || '',
  raw_text: input.text_content || '',
  upload_timestamp: new Date().toISOString(),
  doc_id: `DOC-${Date.now()}-${Math.random().toString(36).substr(2, 6).toUpperCase()}`
};

return [{ json: doc }];

const doc = $('Parse Document Metadata').item.json;
const aiRaw = $input.first().json;

let classification;
try {
  const output = typeof aiRaw.output === 'string' ? aiRaw.output : JSON.stringify(aiRaw.output);
  const cleaned = output.replace(/```json\n?|```/g, '').trim();
  classification = JSON.parse(cleaned);
} catch (e) {
  classification = {
    category: 'OTHER',
    subcategory: 'unclassified',
    title: doc.file_name,
    summary: 'Classification failed - manual review required',
    entities: [],
    keywords: [],
    language: 'en',
    sensitivity: 'internal',
    retention_years: 7,
    action_required: false
  };
}

const enrichedDoc = {
  ...doc,
  classification,
  storage_path: `/${classification.category.toLowerCase()}/${new Date().getFullYear()}/${doc.doc_id}`,
  search_index: [
    classification.title,
    classification.summary,
    ...(classification.keywords || []),
    ...(classification.entities || []),
    classification.category,
    classification.subcategory
  ].join(' ').toLowerCase(),
  processed_at: new Date().toISOString()
};

return [{ json: enrichedDoc }];

